    // 1. Pruning: If any element is not divisible by p, it cannot be part of a subsequence with GCD p.
    const filteredNums = nums.filter(x => x % p === 0);
    const filteredN = filteredNums.length;

    if (filteredN === 0) {
        return false;
    }

    // 2. Check for subsequences of length 1 or more.
    // If we find any element x such that gcd(x/p) = 1, then the subsequence [x] is a good subsequence
    // if and only if n > 1 (since length 1 < n for n > 1).
    // However, the definition is: GCD of the subsequence equals p.
    // If we take a subsequence of length 1, [x], its GCD is x. We need x = p.
    if (nums.includes(p)) {
        // If p itself is in nums, and n > 1, then [p] is a good subsequence (length 1 < n).
        return n > 1;
    }

    // 3. Dynamic Programming / Subset GCD tracking.
    // We are looking for a subsequence S such that gcd(S) = p.
    // Since all elements must be multiples of p, let's normalize the problem:
    // Let b_i = nums[i] / p. We are looking for a subsequence of b's whose GCD is 1,
    // and the original subsequence length must be < n.
    const b = nums.map(x => x / p);

    // We only need to check if there is a subsequence of b's whose GCD is 1.
    // The length constraint (length < n) is tricky because we only care about the existence
    // of *any* good subsequence. If all elements are multiples of p, any subsequence
    // will have a GCD that is a multiple of p. We just need the GCD to be *exactly* p.

    // A simpler approach: Iterate through all non-empty subsequences, but that's O(2^n).
    // Since N is up to 5*10^4, we need a polynomial time solution.

    // Key insight for GCD subsequences:
    // If we can find *any* subsequence S of length L < N such that gcd(S) = p, we return true.
    // If all elements are multiples of p, then gcd(S) = p * gcd(S/p).
    // We need gcd(S/p) = 1.

    // Let b_i = nums[i]/p. We need to know if there's a non-empty subsequence S' of b such that gcd(S') = 1, AND the corresponding original subsequence length L < N.

    // Case 1: L=1. Check if b_i = 1 for any i. (i.e., nums[i] = p). Checked above.
    if (b.includes(1)) return true;

    // Case 2: L >= 2.
    // We can use a variation of subset GCD tracking.
    // Let G be the set of all GCDs achievable by non-empty subsequences of b.
    // Since we only care if 1 is in G, and we want to ensure L < N, we must be careful.

    // If we find any two elements b_i, b_j such that gcd(b_i, b_j) = 1, we are done (L=2 < N, assuming N >= 2).
    if (n >= 2) {
        for (let i = 0; i < filteredN; i++) {
            for (let j = i + 1; j < filteredN; j++) {
                if (gcd(b[i], b[j]) === 1) {
                    return true;
                }
            }
        }
    }

    // If we haven't found a pair, we check if combining three, four, etc., can lead to GCD 1.
    // The set of all achievable GCDs is generally sparse, but potentially large.

    // Given the constraints (N up to 5*10^4), an O(N^2) check is too slow if this function is called many times.
    // However, since we are solving this online, maybe the total number of checks is manageable, or there's a simpler property.

    // Property: If there exists a subsequence S' with GCD 1, then there exists a subsequence of length at most log(max(b_i)) + 1 whose GCD is 1. (Related to basis/linear algebra over Z_p, but for GCD it's simpler).

