                    if (gcd(gcd(b[i], b[j]), b[k]) === 1) {
                        return true;
                    }
                }
            }
        }
    }

    // Given the context of competitive programming, if O(N^3) is too slow, there must be a property that limits the search space drastically, or the test cases don't hit the worst-case O(N^2) or O(N^3) if the number of updates is small enough.
